import UIKit

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    private let validHosts = ["myapp.com"]
    private let validPaths = ["/reset-password"]
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard let host = url.host else { return false }
        
        // Validate host
        guard validHosts.contains(host) else { return false }
        
        // Validate path
        guard let path = url.path else { return false }
        guard validPaths.contains(path) else { return false }
        
        // Extract token parameter
        guard let token = url.queryItems?["token"] else { return false }
        
        // Validate token
        guard !token.isEmpty else { return false }
        
        // Navigate to password reset screen
        navigateToPasswordResetScreen(with: token)
        return true
